css:
.print-heading {
    text-align: center;
    margin-bottom: 30px;
}

.print-heading h2 {
    margin: 0;
    font-size: 18pt;
    font-weight: 700;
    text-transform: uppercase;
}

.print-heading .document-type {
    margin: 7px 0 0;
    font-size: 12pt;
    font-weight: 600;
}

.print-heading .document-name {
    margin: 7px 0 0;
    font-size: 10pt;
    color: #666;
}

.nta-section-heading {
    margin-top: 22px;
    margin-bottom: 10px;
    padding-bottom: 5px;
    border-bottom: 1px solid #b40000;
    font-size: 12pt;
    font-weight: 600;
}

.nta-table {
    width: 100%;
    border-collapse: separate;
    border-spacing: 0;
    border: 1px solid #ddd;
    border-radius: 8px;
    overflow: hidden;
    margin-bottom: 20px;
}

.nta-table th,
.nta-table td {
    padding: 8px;
    vertical-align: top;
}

.nta-table th {
    background-color: #f5f5f5;
    border-bottom: 1px solid #ddd;
    font-weight: 600;
    text-align: left;
}

.nta-table td {
    border-bottom: 1px solid #ddd;
    border-right: 1px solid #ddd;
}

.nta-table td:last-child,
.nta-table th:last-child {
    border-right: none;
}

.nta-table tbody tr:last-child td {
    border-bottom: none;
}

.nta-table tbody tr:nth-child(odd) {
    background-color: #fafafa;
}

.nta-notice {
    margin: 15px 0 20px;
    padding: 12px;
    border: 1px solid #ddd;
    border-left: 4px solid #b40000;
    border-radius: 4px;
    background-color: #fafafa;
}

.nta-notice p {
    margin: 0 0 8px;
}

.nta-notice p:last-child {
    margin-bottom: 0;
}

.nta-emphasis {
    font-weight: 700;
}

.nta-no-data {
    color: #777;
    font-style: italic;
}

.nta-rights-list {
    margin: 0;
    padding-left: 20px;
}

.nta-rights-list li {
    margin-bottom: 6px;
}

.signatures {
  margin-top: 34px;
  page-break-inside: avoid;
}

.signatures table {
  width: 100%;
  border-collapse: collapse;
}

.signatures td {
  width: 50%;
  padding: 18px 24px 14px 0;
  border: none;
  vertical-align: bottom;
}

.signatures td:nth-child(even) {
  padding-right: 0;
}

.signature-space {
  height: 34px;
}

.signature-line {
  width: 100%;
  margin-bottom: 5px;
  border-top: 1px solid #333;
}

.signatures p {
  margin: 0;
  font-size: 9pt;
}

@page {
    @bottom-right {
        content: "Page " counter(page) " of " counter(pages);
        font-size: 10pt;
        color: #999;
    }
}
